package com.seaquake6324.civitas.application;
import com.seaquake6324.civitas.application.port.PopulationRepository;import com.seaquake6324.civitas.domain.population.*;
/** Converts an active marriage into immutable household history after a permanent NPC death. */
public final class RecordPartnerDeathService{public Result record(PopulationRepository repository,CitizenRecord deceased){if(deceased.alive())return new Result(false,Failure.NOT_DEAD,null);if(deceased.householdId()==null)return new Result(true,null,null);Household household=repository.household(deceased.householdId()).orElse(null);if(household==null)return new Result(false,Failure.MISSING_HOUSEHOLD,null);FamilyMemberRef ref=FamilyMemberRef.citizen(deceased.id());if(!household.partners().contains(ref))return new Result(true,null,household);boolean applied=repository.recordPartnerDeath(household.id(),ref,household.revision());return applied?new Result(true,null,household.recordPartnerDeath(ref)):new Result(false,Failure.STALE_HOUSEHOLD,household);}public enum Failure{NOT_DEAD,MISSING_HOUSEHOLD,STALE_HOUSEHOLD}public record Result(boolean success,Failure failure,Household household){} }
